# @cctt_verify {"v":2,"sym":"sympy.integrals.tests.test_integrals.diff_test","kind":"function","src_hash":"3d27e844e8a7deec","in":{"base":"Any","pred":"hasattr(i, 'free_symbols') and hasattr(i, 'diff') and hasattr(i, 'doit')"},"out":{"base":"Any","pred":"(i.diff(s).doit() - i.doit().diff(s)).expand() == 0"},"spec":{"lhs":"diff_test(i)","rhs":"<unspecified:diff_test>","over":{"base":"Any","pred":"hasattr(i, 'free_symbols') and hasattr(i, 'diff') and hasattr(i, 'doit')"},"name":"diff_test_correct"},"guarantee":"return the set of symbols, s, which were used in testing that i.diff(s) agrees with i.doit().diff(s)","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.integrals.tests.test_integrals.diff_test_correct","statement":"Path(diff_test(x), return the set of symbols, s, which were used in testing that i.diff(s) agrees with i.doit().diff(s))"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"a3902edb4c0db095","spec_source":"static","formal_spec":{"source":"static","strength":"trivial","requires":["hasattr(i, 'free_symbols')","hasattr(i, 'diff')","hasattr(i, 'doit')"],"pure":false,"effects":{"effect_type":"reads_state","reads":["i.diff","i.doit","i.free_symbols"]}},"c4_verdict":{"valid":true,"n_vcs":1,"n_verified":0,"n_assumed":1,"n_failed":0,"trust_level":"LIBRARY_ASSUMED","compile_ms":0.1,"verdict_class":"assumed","binding":true}}
def diff_test(i):
    """Return the set of symbols, s, which were used in testing that
    i.diff(s) agrees with i.doit().diff(s). If there is an error then
    the assertion will fail, causing the test to fail."""
    syms = i.free_symbols
    for s in syms:
        assert (i.diff(s).doit() - i.doit().diff(s)).expand() == 0
    return syms


