# @cctt_verify {"v":2,"sym":"sympy.integrals.tests.test_integrals.test_issue_17473","kind":"function","src_hash":"cfcbf2bba7c59954","in":{"base":"Any"},"out":{"base":"Any","pred":"result satisfies: got == ans and integrate(sin(_x ** n), _x) == ans.xreplace(reps).expand()"},"spec":{"lhs":"test_issue_17473()","rhs":"got == ans and integrate(sin(_x ** n), _x) == ans.xreplace(reps).expand()","over":{"base":"Any"},"name":"test_issue_17473_correct"},"guarantee":"got == ans; integrate(sin(_x ** n), _x) == ans.xreplace(reps).expand()","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.integrals.tests.test_integrals.test_issue_17473_correct","statement":"Path(test_issue_17473(x), got == ans; integrate(sin(_x ** n), _x) == ans.xreplace(reps).expand())"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"a14a1240486f2d7b","spec_source":"static","formal_spec":{"source":"static","strength":"formal","ensures":["got == ans","integrate(sin(_x ** n), _x) == ans.xreplace(reps).expand()"],"pure":true},"c4_verdict":{"valid":true,"n_vcs":1,"n_verified":0,"n_assumed":1,"n_failed":0,"trust_level":"LIBRARY_ASSUMED","compile_ms":0.2,"verdict_class":"assumed","binding":true}}
def test_issue_17473():
    x = Symbol('x')
    n = Symbol('n')
    h = S.Half
    ans = x**(n + 1)*gamma(h + h/n)*hyper((h + h/n,),
        (3*h, 3*h + h/n), -x**(2*n)/4)/(2*n*gamma(3*h + h/n))
    got = integrate(sin(x**n), x)
    assert got == ans
    _x = Symbol('x', zero=False)
    reps = {x: _x}
    assert integrate(sin(_x**n), _x) == ans.xreplace(reps).expand()


