# @cctt_verify {"v":2,"sym":"sympy.integrals.tests.test_integrals.test_issue_23718","kind":"function","src_hash":"4fce72a886078a5d","in":{"base":"Any"},"out":{"base":"Any","pred":"result satisfies: integrate(f, x) == F and integrate(f.subs(rep), x) == Fpos.subs(rep)"},"spec":{"lhs":"test_issue_23718()","rhs":"integrate(f, x) == F and integrate(f.subs(rep), x) == Fpos.subs(rep)","over":{"base":"Any"},"name":"test_issue_23718_correct"},"guarantee":"integrate(f, x) == F; integrate(f.subs(rep), x) == Fpos.subs(rep)","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.integrals.tests.test_integrals.test_issue_23718_correct","statement":"Path(test_issue_23718(x), integrate(f, x) == F; integrate(f.subs(rep), x) == Fpos.subs(rep))"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"641cfccd72efef6e","spec_source":"static","formal_spec":{"source":"static","strength":"formal","ensures":["integrate(f, x) == F","integrate(f.subs(rep), x) == Fpos.subs(rep)"],"pure":true},"c4_verdict":{"valid":true,"n_vcs":1,"n_verified":0,"n_assumed":1,"n_failed":0,"trust_level":"LIBRARY_ASSUMED","compile_ms":0.4,"verdict_class":"assumed","binding":true}}
def test_issue_23718():
    f = 1/(b*cos(x) + a*sin(x))
    Fpos = (-log(-a/b + tan(x/2) - sqrt(a**2 + b**2)/b)/sqrt(a**2 + b**2)
            +log(-a/b + tan(x/2) + sqrt(a**2 + b**2)/b)/sqrt(a**2 + b**2))
    F = Piecewise(
        # XXX: The zoo case here is for a=b=0 so it should just be zoo or maybe
        # it doesn't really need to be included at all given that the original
        # integrand is really undefined in that case anyway.
        (zoo*(-log(tan(x/2) - 1) + log(tan(x/2) + 1)),  Eq(a, 0) & Eq(b, 0)),
        (log(tan(x/2))/a,                               Eq(b, 0)),
        (-I/(-I*b*sin(x) + b*cos(x)),                   Eq(a, -I*b)),
        (I/(I*b*sin(x) + b*cos(x)),                     Eq(a,  I*b)),
        (Fpos,                                          True),
    )
    assert integrate(f, x) == F

    ap, bp = symbols('a, b', positive=True)
    rep = {a: ap, b: bp}
    assert integrate(f.subs(rep), x) == Fpos.subs(rep)


